// Procesar datos de entrada y simular OCR
const inputData = $input.first().json;

// Extraer datos del webhook
const filename = inputData.filename || 'unknown.pdf';
const provider = inputData.provider || 'unknown';
const pdf_url = inputData.pdf_url || '';

// Simular extracción de datos OCR
const invoiceData = {
  invoice_number: 'INV-' + Math.floor(Math.random() * 100000),
  date: new Date().toISOString().split('T')[0],
  supplier: provider,
  total: (Math.random() * 1000 + 100).toFixed(2),
  currency: 'EUR',
  tax_amount: (Math.random() * 100 + 10).toFixed(2),
  items: [
    {
      description: 'Servicio profesional',
      quantity: 1,
      unit_price: (Math.random() * 500 + 50).toFixed(2),
      total: (Math.random() * 500 + 50).toFixed(2)
    }
  ]
};

// Enmascarar datos sensibles (Antonio)
if (invoiceData.supplier && invoiceData.supplier.toLowerCase().includes('antonio')) {
  invoiceData.supplier = invoiceData.supplier.replace(/antonio/gi, 'A***o');
}

// Resultado final
const result = {
  success: true,
  timestamp: new Date().toISOString(),
  source: 'simulated-ocr',
  processing_time: Math.floor(Math.random() * 5000) + 1000,
  data: invoiceData,
  metadata: {
    original_filename: filename,
    source_url: pdf_url,
    provider: provider,
    test_mode: inputData.test_mode || false
  }
};

return [result];
